   227→        await this.prisma.detectedAttribute.createMany({ data: attributeData });
   228→      }
   229→    } catch (error) {
   230→      throw new Error(`Failed to save attribute context: ${error instanceof Error ? error.message : String(error)}`);
   231→    }
   232→  }
   233→
   234→  /**
   235→   * Save domain signal resolutions
   236→   *
   237→   * @param signals - Array of domain signal resolutions
   238→   * @param sessionId - Session identifier as string (from createSession)
   239→   * @throws {Error} If save fails
   240→   */
   241→  async saveDomainSignals(signals: DomainSignalData[], sessionId: string): Promise<void> {
   242→    if (signals.length === 0) {
   243→      return;
   244→    }
   245→
   246→    try {
   247→      const dbSessionId = BigInt(sessionId);
   248→      await this.prisma.domainSignalResolution.createMany({
   249→        data: signals.map((signal) => ({
   250→          sessionId: dbSessionId,
   251→          domain: signal.domain,
   252→          signalType: signal.signalType,
   253→          matchedCategoryId: signal.matchedCategoryId,
   254→          confidenceLevel: signal.confidenceLevel || null,
   255→          domainType: signal.domainType || null,
   256→          createdAt: new Date(),
   257→        })),
   258→      });
   259→    } catch (error) {
   260→      throw new Error(`Failed to save domain signals: ${error instanceof Error ? error.message : String(error)}`);
   261→    }
   262→  }
   263→
   264→  /**
   265→   * Batch save multiple classification results
   266→   *
   267→   * @param results - Array of ClassificationResult objects
   268→   * @param sessionId - Session identifier as string (from createSession)
   269→   * @throws {Error} If batch save fails
   270→   */
   271→  async batchSaveResults(results: ClassificationResult[], sessionId: string): Promise<void> {
   272→    if (results.length === 0) {
   273→      return;
   274→    }
   275→
   276→    try {
   277→      // Save each result sequentially within a transaction
   278→      for (const result of results) {
   279→        await this.saveClassificationResult(result, sessionId);
   280→      }
   281→    } catch (error) {
   282→      throw new Error(
   283→        `Failed to batch save classification results: ${error instanceof Error ? error.message : String(error)}`
   284→      );
   285→    }
   286→  }
   287→
   288→  /**
   289→   * Build classification stage data from explainability trace
   290→   */
   291→  private buildStageData(
   292→    result: ClassificationResult,
   293→    sessionId: bigint
   294→  ): Array<Prisma.ClassificationStageCreateManyInput> {
   295→    const stages: Array<Prisma.ClassificationStageCreateManyInput> = [];
   296→    const trace = result.explainabilityTrace;
   297→
   298→    // Map pipeline stages to database records
   299→    const stageMapping = [
   300→      { order: 1, type: 'hard_assertions', data: trace.hardAssertions },
   301→      { order: 2, type: 'strong_indicators', data: trace.strongIndicators },
   302→      { order: 3, type: 'rule_scoring', data: trace.ruleScoring },
   303→      { order: 4, type: 'attribute_detection', data: trace.attributeDetection },
   304→      { order: 5, type: 'attribute_influence', data: trace.attributeInfluence },
   305→      { order: 6, type: 'disambiguation', data: trace.disambiguation },
   306→      { order: 7, type: 'multi_label_selection', data: trace.multiLabelSelection },
   307→      { order: 8, type: 'ai_routing', data: trace.aiRouting },
   308→      { order: 9, type: 'final_decision', data: { reason: trace.finalDecisionReason } },
   309→      {
   310→        order: 10,
   311→        type: 'action_determination',
   312→        data: {
   313→          determinedActions: result.determinedActions || [],
   314→          actionReasoning: result.finalClassificationSummary?.determinedActions
   315→            ? `Actions: ${result.finalClassificationSummary.determinedActions.join(', ')}`
   316→            : 'No actions determined',
   317→        },
   318→      },
   319→    ];
   320→
   321→    for (const stage of stageMapping) {
   322→      stages.push({
   323→        sessionId: sessionId,
   324→        stageOrder: stage.order,
   325→        stageType: stage.type,
   326→        startedAt: new Date(),
   327→        endedAt: new Date(),
   328→        features: stage.data as Prisma.InputJsonValue,
   329→        keywords: [],
   330→        passedToNext: true,
   331→      });
   332→    }
   333→
   334→    return stages;
   335→  }
   336→
   337→  /**
   338→   * Build stage category evaluation data from score breakdown
   339→   */
   340→  private async buildCategoryEvalData(
   341→    result: ClassificationResult,
   342→    sessionId: bigint
   343→  ): Promise<Array<Prisma.StageCategoryEvalCreateManyInput>> {
   344→    const evaluations: Array<Prisma.StageCategoryEvalCreateManyInput> = [];
   345→    const scoreBreakdown = result.scoreBreakdown;
   346→
   347→    // Extract category scores and create evaluations
   348→    for (const [category, scores] of Object.entries(scoreBreakdown.categoryScores || {})) {
   349→      try {
   350→        const categoryId = await this.getCategoryIdFromCode(category);
   351→        evaluations.push({
   352→          stageId: sessionId, // Simplified: using session_id as stage_id for MVP
   353→          categoryId: categoryId,
   354→          decision: result.selectedLabels.some((label) => label.category === category) ? 'positive' : 'candidate',
   355→          score: scores as unknown as Prisma.InputJsonValue,
   356→          confidence: new Prisma.Decimal(scores.finalScore || 0),
   357→          scoringComponents: scores as unknown as Prisma.InputJsonValue,
   358→          keywords: [],
   359→          createdAt: new Date(),
   360→        });
   361→      } catch (error) {
   362→        // Log warning and skip unknown category (graceful degradation)
   363→        console.warn(
   364→          `Skipping category evaluation for unknown category '${category}': ${error instanceof Error ? error.message : String(error)}`
   365→        );
   366→      }
   367→    }
   368→
   369→    return evaluations;
   370→  }
   371→
   372→  /**
   373→   * Build session category data (multi-label support)
   374→   */
   375→  private async buildSessionCategoryData(
   376→    result: ClassificationResult,
   377→    sessionId: bigint
   378→  ): Promise<Array<Prisma.SessionCategoryCreateManyInput>> {
   379→    const categories: Array<Prisma.SessionCategoryCreateManyInput> = [];
   380→
   381→    for (const label of result.selectedLabels) {
   382→      try {
   383→        const categoryId = await this.getCategoryIdFromCode(label.category);
   384→        const subtypeId = label.subtype ? await this.getCategoryIdFromCode(label.subtype) : null;
   385→
   386→        categories.push({
   387→          sessionId: sessionId,
   388→          categoryId: categoryId,
   389→          subtypeId: subtypeId,
   390→          isPrimary: label.isPrimary,
   391→          confidence: new Prisma.Decimal(label.confidence),
   392→          categoryScore: new Prisma.Decimal(label.score),
   393→          hardAssertion: false, // TODO: Extract from explainability trace
   394→          aiClassified: result.aiRoutingUsed,
   395→          scoringTrace: result.scoreBreakdown as unknown as Prisma.InputJsonValue,
   396→          labelOrder: label.labelOrder,
   397→          createdAt: new Date(),
   398→        });
   399→      } catch (error) {
   400→        // Log warning and skip unknown category (graceful degradation)
   401→        console.warn(
   402→          `Skipping session category for unknown category '${label.category}': ${error instanceof Error ? error.message : String(error)}`
   403→        );
   404→      }
   405→    }
   406→
   407→    return categories;
   408→  }
   409→
   410→  /**
   411→   * Build detected attribute data from attribute context
   412→   */
   413→  private buildAttributeData(
   414→    context: AttributeContext,
   415→    sessionId: bigint
   416→  ): Array<Prisma.DetectedAttributeCreateManyInput> {
   417→    const attributes: Array<Prisma.DetectedAttributeCreateManyInput> = [];
   418→
   419→    // Add urgency attribute
   420→    attributes.push({
   421→      sessionId: sessionId,
   422→      attributeName: 'urgency',
   423→      attributeValue: context.urgency,
   424→      detectionMethod: 'rule',
   425→      detectionEvidence: 'Urgency level detection',
   426→      influenceRole: 'FILTER',
   427→      categoriesInfluenced: [],
   428→      totalBonusApplied: new Prisma.Decimal(0),
   429→      createdAt: new Date(),
   430→    });
   431→
   432→    // Add domain attributes
   433→    for (const domain of context.domains) {
   434→      attributes.push({
   435→        sessionId: sessionId,
   436→        attributeName: `domain:${domain}`,
   437→        attributeValue: domain,
   438→        detectionMethod: 'domain_lookup',
   439→        detectionEvidence: `Domain ${domain} detected`,
   440→        influenceRole: 'CORE',
   441→        categoriesInfluenced: [],
   442→        totalBonusApplied: new Prisma.Decimal(0),
   443→        createdAt: new Date(),
   444→      });
   445→    }
   446→
   447→    // Add structural pattern attributes
   448→    for (const pattern of context.structuralPatterns) {
   449→      attributes.push({
   450→        sessionId: sessionId,
   451→        attributeName: `pattern:${pattern}`,
   452→        attributeValue: pattern,
   453→        detectionMethod: 'regex',
   454→        detectionEvidence: `Pattern ${pattern} matched`,
   455→        influenceRole: 'SECONDARY_BOOST',
   456→        categoriesInfluenced: [],
   457→        totalBonusApplied: new Prisma.Decimal(0),
   458→        createdAt: new Date(),
   459→      });
   460→    }
   461→
   462→    return attributes;
   463→  }
   464→
   465→  /**
   466→   * Build extracted feature data from AI feature extraction results
   467→   *
   468→   * Extracts AI-generated features from the explainability trace and creates
   469→   * database records linked to the AI routing stage (stage 8).
   470→   *
   471→   * Only called when AI routing was used (result.aiRoutingUsed = true).
   472→   *
   473→   * @param result - ClassificationResult with AI feature extraction data
   474→   * @param stageRecords - Created classification stages with IDs
   475→   * @returns Array of extracted feature records for database insertion
   476→   */
   477→  private buildExtractedFeatureData(
   478→    result: ClassificationResult,
   479→    stageRecords: Array<{ stageId: bigint; stageOrder: number }>
   480→  ): Array<Prisma.ExtractedFeatureCreateManyInput> {
   481→    const features: Array<Prisma.ExtractedFeatureCreateManyInput> = [];
   482→
   483→    // Find the AI routing stage (stage 8) to associate features with
   484→    const aiRoutingStage = stageRecords.find((stage) => stage.stageOrder === 8);
   485→    if (!aiRoutingStage) {
   486→      console.warn('AI routing stage not found in stage records, skipping feature extraction persistence');
   487→      return features;
   488→    }
   489→
   490→    // Extract AI feature extraction data from explainability trace
   491→    const aiResponse = result.explainabilityTrace?.aiRouting?.aiResponse;
   492→    if (!aiResponse?.extractedFeatures) {
   493→      // No AI features to persist (AI routing may have skipped feature extraction)
   494→      return features;
   495→    }
   496→
   497→    const extractedFeatures = aiResponse.extractedFeatures as {
   498→      semanticIntent?: {
   499→        primaryPurpose?: string;
   500→        actionRequired?: string;
   501→        urgencyLevel?: string;
   502→      };
   503→      categoryEnhancements?: Record<
   504→        string,
   505→        {
   506→          applies: boolean;
   507→          confidenceBoost: number;
   508→          evidence?: {
   509→            quotedPhrases?: string[];
   510→            keywords?: string[];
   511→            reasoning?: string;
   512→          };
   513→        }
   514→      >;
   515→    };
   516→
   517→    // Extract semantic intent features
   518→    if (extractedFeatures.semanticIntent) {
   519→      const intent = extractedFeatures.semanticIntent;
   520→
   521→      if (intent.primaryPurpose) {
   522→        features.push({
   523→          stageId: aiRoutingStage.stageId,
   524→          name: 'semantic_intent_primary_purpose',
   525→          value: intent.primaryPurpose,
   526→          importance: new Prisma.Decimal(0.8), // High importance for primary purpose
   527→          evidenceSnippet: null,
   528→          createdAt: new Date(),
   529→        });
   530→      }
   531→
   532→      if (intent.actionRequired) {
   533→        features.push({
   534→          stageId: aiRoutingStage.stageId,
   535→          name: 'semantic_intent_action_required',
   536→          value: intent.actionRequired,
   537→          importance: new Prisma.Decimal(0.7),
   538→          evidenceSnippet: null,
   539→          createdAt: new Date(),
   540→        });
   541→      }
   542→
   543→      if (intent.urgencyLevel) {
   544→        features.push({
   545→          stageId: aiRoutingStage.stageId,
   546→          name: 'semantic_intent_urgency_level',
   547→          value: intent.urgencyLevel,
   548→          importance: new Prisma.Decimal(0.6),
   549→          evidenceSnippet: null,
   550→          createdAt: new Date(),
   551→        });
   552→      }
   553→    }
   554→
   555→    // Extract category enhancement features
   556→    if (extractedFeatures.categoryEnhancements) {
   557→      for (const [category, enhancement] of Object.entries(extractedFeatures.categoryEnhancements)) {
   558→        if (enhancement.applies && enhancement.confidenceBoost > 0) {
   559→          // Create a feature record for this category enhancement
   560→          const evidenceSnippet =
   561→            enhancement.evidence?.quotedPhrases && enhancement.evidence.quotedPhrases.length > 0
   562→              ? enhancement.evidence.quotedPhrases.slice(0, 3).join(' | ') // First 3 quoted phrases
   563→              : enhancement.evidence?.reasoning || null;
   564→
   565→          features.push({
   566→            stageId: aiRoutingStage.stageId,
   567→            name: `category_enhancement_${category}`,
   568→            value: `boost:${enhancement.confidenceBoost}`,
   569→            importance: new Prisma.Decimal(Math.min(enhancement.confidenceBoost / 100, 1.0)), // Normalize to 0-1
   570→            evidenceSnippet: evidenceSnippet ? evidenceSnippet.substring(0, 500) : null, // Limit length
   571→            createdAt: new Date(),
   572→          });
   573→
   574→          // If there are keywords, create a separate feature for them
   575→          if (enhancement.evidence?.keywords && enhancement.evidence.keywords.length > 0) {
   576→            features.push({
   577→              stageId: aiRoutingStage.stageId,
   578→              name: `category_keywords_${category}`,
   579→              value: enhancement.evidence.keywords.slice(0, 10).join(', '), // First 10 keywords
   580→              importance: new Prisma.Decimal(0.5),
   581→              evidenceSnippet: null,
   582→              createdAt: new Date(),
   583→            });
   584→          }
   585→        }
   586→      }
   587→    }
   588→
   589→    return features;
   590→  }
   591→
   592→  /**
   593→   * Get category ID from category code
   594→   *
   595→   * Uses cached category lookup for performance. Cache is initialized
   596→   * on first use and persists for the lifetime of the repository instance.
   597→   *
   598→   * @param code - Category code (e.g., 'finance', 'personal')
   599→   * @returns Category ID from database
   600→   * @throws {Error} If category code not found in database
   601→   */
   602→  private async getCategoryIdFromCode(code: string): Promise<number> {
   603→    // Initialize cache on first use
   604→    if (this.categoryCache === null) {
   605→      await this.initializeCategoryCache();
   606→    }
   607→
   608→    const categoryId = this.categoryCache!.get(code);
   609→    if (categoryId === undefined) {
   610→      throw new Error(
   611→        `Category code '${code}' not found in database. Available categories: ${Array.from(this.categoryCache!.keys()).join(', ')}`
   612→      );
   613→    }
   614→
   615→    return categoryId;
   616→  }
   617→
   618→  /**
   619→   * Close the Prisma client connection
   620→   *
   621→   * Only closes if using default Prisma instance (not externally provided).
   622→   */
   623→  async close(): Promise<void> {
   624→    if (this.ownsPrisma) {
   625→      await this.prisma.$disconnect();
   626→    }
   627→  }
   628→}
