     1→/**
     2→ * Classification Results Persistence Layer (T043) - Prisma Implementation
     3→ *
     4→ * Repository pattern for classification results persistence using Prisma ORM:
     5→ * - Classification session management (create, update, complete)
     6→ * - Classification results with explainability traces
     7→ * - Score breakdown persistence
     8→ * - Attribute context storage
     9→ * - Multi-label classification support
    10→ * - Domain signal resolutions
    11→ * - Transaction-safe batch operations
    12→ *
    13→ * Benefits of Prisma ORM:
    14→ * - Type-safe database queries with auto-generated types
    15→ * - Built-in transaction handling for complex multi-table operations
    16→ * - Automatic JSON serialization/deserialization for explainability data
    17→ * - Connection pooling and query optimization
    18→ * - SQL injection protection via parameterized queries
    19→ */
    20→
    21→import { PrismaClient, Prisma } from '@prisma/client';
    22→import { ClassificationResult, ClassificationSession, AttributeContext } from '@gmail-automation/classification-engine';
    23→
    24→/**
    25→ * Domain signal resolution data structure
    26→ */
    27→export interface DomainSignalData {
    28→  domain: string;
    29→  signalType: 'hard_assertion' | 'strong_indicator' | 'weak_signal';
    30→  matchedCategoryId: number | null;
    31→  confidenceLevel?: string;
    32→  domainType?: string;
    33→}
    34→
    35→/**
    36→ * Classification Repository using Prisma ORM
    37→ *
    38→ * Provides type-safe classification results persistence with automatic transaction
    39→ * handling, connection pooling, and explainability trace integrity.
    40→ */
    41→export class ClassificationRepository {
    42→  private readonly prisma: PrismaClient;
    43→  private readonly ownsPrisma: boolean;
    44→  private categoryCache: Map<string, number> | null = null;
    45→
    46→  /**
    47→   * Initialize classification repository
    48→   *
    49→   * @param prisma - Optional Prisma client instance (creates default if not provided)
    50→   */
    51→  constructor(prisma?: PrismaClient) {
    52→    if (prisma) {
    53→      this.prisma = prisma;
    54→      this.ownsPrisma = false;
    55→    } else {
    56→      this.prisma = new PrismaClient();
    57→      this.ownsPrisma = true;
    58→    }
    59→  }
    60→
    61→  /**
    62→   * Initialize category cache from database
    63→   *
    64→   * Loads all active categories into memory for fast lookup by code.
    65→   * Called automatically on first use of getCategoryIdFromCode().
    66→   *
    67→   * @throws {Error} If category loading fails
    68→   */
    69→  private async initializeCategoryCache(): Promise<void> {
    70→    try {
    71→      const categories = await this.prisma.category.findMany({
    72→        where: { active: true },
    73→        select: { code: true, categoryId: true },
    74→      });
    75→
    76→      this.categoryCache = new Map(categories.map((cat) => [cat.code, cat.categoryId]));
    77→    } catch (error) {
    78→      throw new Error(`Failed to load category cache: ${error instanceof Error ? error.message : String(error)}`);
    79→    }
    80→  }
    81→
    82→  /**
    83→   * Create a new classification session
    84→   *
    85→   * @param session - ClassificationSession object
    86→   * @param gmailId - Gmail message ID being classified
    87→   * @returns Database session ID as string (safe representation of bigint)
    88→   * @throws {Error} If session creation fails
    89→   */
    90→  async createSession(session: ClassificationSession, gmailId: string): Promise<string> {
    91→    try {
    92→      const result = await this.prisma.classificationSession.create({
    93→        data: {
    94→          gmailId: gmailId,
    95→          pipelineVersion: session.configVersion,
    96→          startedAt: session.startedAt,
    97→          status: 'in_progress',
    98→          triggeredBy: 'system',
    99→          aiRoutingUsed: false,
   100→        },
   101→      });
   102→
   103→      return result.sessionId.toString();
   104→    } catch (error) {
   105→      throw new Error(
   106→        `Failed to create classification session: ${error instanceof Error ? error.message : String(error)}`
   107→      );
   108→    }
   109→  }
   110→
   111→  /**
   112→   * Complete a classification session
   113→   *
   114→   * @param sessionId - Session identifier as string (from createSession)
   115→   * @param finalCategoryId - Final category ID selected
   116→   * @param confidence - Final confidence score
   117→   * @param rationale - Final decision rationale
   118→   * @throws {Error} If session update fails
   119→   */
   120→  async completeSession(
   121→    sessionId: string,
   122→    finalCategoryId: number,
   123→    confidence: number,
   124→    rationale: string
   125→  ): Promise<void> {
   126→    try {
   127→      // Convert string session ID to BigInt for database query
   128→      const dbSessionId = BigInt(sessionId);
   129→
   130→      await this.prisma.classificationSession.update({
   131→        where: { sessionId: dbSessionId },
   132→        data: {
   133→          completedAt: new Date(),
   134→          finalCategoryId: finalCategoryId,
   135→          finalConfidence: new Prisma.Decimal(confidence),
   136→          finalRationale: rationale,
   137→          status: 'completed',
   138→        },
   139→      });
   140→    } catch (error) {
   141→      throw new Error(
   142→        `Failed to complete session ${sessionId}: ${error instanceof Error ? error.message : String(error)}`
   143→      );
   144→    }
   145→  }
   146→
   147→  /**
   148→   * Save complete classification result with explainability trace
   149→   *
   150→   * Uses Prisma transaction to ensure atomicity across multiple tables:
   151→   * - classification_stage (10 pipeline stages)
   152→   * - stage_category_eval (per-category evaluations)
   153→   * - session_categories (multi-label support)
   154→   * - detected_attributes (attribute context)
   155→   * - extracted_features (AI feature extraction data, if AI was used)
   156→   * - domain_signal_resolutions (domain signals)
   157→   *
   158→   * @param result - ClassificationResult with explainability trace
   159→   * @param sessionId - Session identifier as string (from createSession)
   160→   * @throws {Error} If save fails (rolls back entire transaction)
   161→   */
   162→  async saveClassificationResult(result: ClassificationResult, sessionId: string): Promise<void> {
   163→    try {
   164→      const dbSessionId = BigInt(sessionId);
   165→
   166→      await this.prisma.$transaction(async (tx) => {
   167→        // 1. Create classification stages (10 pipeline stages: hard assertions through action determination)
   168→        const stageData = this.buildStageData(result, dbSessionId);
   169→        let stageRecords: Array<{ stageId: bigint; stageOrder: number }> = [];
   170→        if (stageData.length > 0) {
   171→          await tx.classificationStage.createMany({ data: stageData });
   172→
   173→          // Retrieve created stage records to get stage IDs for AI feature extraction
   174→          stageRecords = await tx.classificationStage.findMany({
   175→            where: { sessionId: dbSessionId },
   176→            select: { stageId: true, stageOrder: true },
   177→            orderBy: { stageOrder: 'asc' },
   178→          });
   179→        }
   180→
   181→        // 2. Create stage category evaluations (score breakdown for each category)
   182→        const categoryEvalData = await this.buildCategoryEvalData(result, dbSessionId);
   183→        if (categoryEvalData.length > 0) {
   184→          await tx.stageCategoryEval.createMany({ data: categoryEvalData });
   185→        }
   186→
   187→        // 3. Create session categories (multi-label support)
   188→        const sessionCategoryData = await this.buildSessionCategoryData(result, dbSessionId);
   189→        if (sessionCategoryData.length > 0) {
   190→          await tx.sessionCategory.createMany({ data: sessionCategoryData });
   191→        }
   192→
   193→        // 4. Create detected attributes (attribute context)
   194→        const attributeData = this.buildAttributeData(result.attributeContext, dbSessionId);
   195→        if (attributeData.length > 0) {
   196→          await tx.detectedAttribute.createMany({ data: attributeData });
   197→        }
   198→
   199→        // 5. Create extracted features (AI feature extraction data)
   200→        // Only persist if AI routing was used and we have feature extraction data
   201→        if (result.aiRoutingUsed && stageRecords.length > 0) {
   202→          const extractedFeatureData = this.buildExtractedFeatureData(result, stageRecords);
   203→          if (extractedFeatureData.length > 0) {
   204→            await tx.extractedFeature.createMany({ data: extractedFeatureData });
   205→          }
   206→        }
   207→      });
   208→    } catch (error) {
   209→      throw new Error(
   210→        `Failed to save classification result for email ${result.emailId}: ${error instanceof Error ? error.message : String(error)}`
   211→      );
   212→    }
   213→  }
   214→
   215→  /**
   216→   * Save attribute context separately
   217→   *
   218→   * @param context - AttributeContext with detected attributes
   219→   * @param sessionId - Session identifier as string (from createSession)
   220→   * @throws {Error} If save fails
   221→   */
   222→  async saveAttributeContext(context: AttributeContext, sessionId: string): Promise<void> {
   223→    try {
   224→      const dbSessionId = BigInt(sessionId);
   225→      const attributeData = this.buildAttributeData(context, dbSessionId);
   226→      if (attributeData.length > 0) {
   227→        await this.prisma.detectedAttribute.createMany({ data: attributeData });
   228→      }
   229→    } catch (error) {
   230→      throw new Error(`Failed to save attribute context: ${error instanceof Error ? error.message : String(error)}`);
   231→    }
   232→  }
   233→
   234→  /**
   235→   * Save domain signal resolutions
   236→   *
   237→   * @param signals - Array of domain signal resolutions
   238→   * @param sessionId - Session identifier as string (from createSession)
   239→   * @throws {Error} If save fails
   240→   */
   241→  async saveDomainSignals(signals: DomainSignalData[], sessionId: string): Promise<void> {
   242→    if (signals.length === 0) {
   243→      return;
   244→    }
   245→
   246→    try {
   247→      const dbSessionId = BigInt(sessionId);
   248→      await this.prisma.domainSignalResolution.createMany({
   249→        data: signals.map((signal) => ({
   250→          sessionId: dbSessionId,
   251→          domain: signal.domain,
   252→          signalType: signal.signalType,
   253→          matchedCategoryId: signal.matchedCategoryId,
   254→          confidenceLevel: signal.confidenceLevel || null,
   255→          domainType: signal.domainType || null,
   256→          createdAt: new Date(),
   257→        })),
   258→      });
   259→    } catch (error) {
   260→      throw new Error(`Failed to save domain signals: ${error instanceof Error ? error.message : String(error)}`);
   261→    }
   262→  }
   263→
   264→  /**
   265→   * Batch save multiple classification results
   266→   *
   267→   * @param results - Array of ClassificationResult objects
   268→   * @param sessionId - Session identifier as string (from createSession)
   269→   * @throws {Error} If batch save fails
   270→   */
   271→  async batchSaveResults(results: ClassificationResult[], sessionId: string): Promise<void> {
   272→    if (results.length === 0) {
   273→      return;
   274→    }
   275→
   276→    try {
   277→      // Save each result sequentially within a transaction
   278→      for (const result of results) {
   279→        await this.saveClassificationResult(result, sessionId);
   280→      }
   281→    } catch (error) {
   282→      throw new Error(
   283→        `Failed to batch save classification results: ${error instanceof Error ? error.message : String(error)}`
   284→      );
   285→    }
   286→  }
   287→
   288→  /**
   289→   * Build classification stage data from explainability trace
   290→   */
   291→  private buildStageData(
   292→    result: ClassificationResult,
   293→    sessionId: bigint
   294→  ): Array<Prisma.ClassificationStageCreateManyInput> {
   295→    const stages: Array<Prisma.ClassificationStageCreateManyInput> = [];
   296→    const trace = result.explainabilityTrace;
   297→
   298→    // Map pipeline stages to database records
   299→    const stageMapping = [
   300→      { order: 1, type: 'hard_assertions', data: trace.hardAssertions },
   301→      { order: 2, type: 'strong_indicators', data: trace.strongIndicators },
   302→      { order: 3, type: 'rule_scoring', data: trace.ruleScoring },
   303→      { order: 4, type: 'attribute_detection', data: trace.attributeDetection },
   304→      { order: 5, type: 'attribute_influence', data: trace.attributeInfluence },
   305→      { order: 6, type: 'disambiguation', data: trace.disambiguation },
   306→      { order: 7, type: 'multi_label_selection', data: trace.multiLabelSelection },
   307→      { order: 8, type: 'ai_routing', data: trace.aiRouting },
   308→      { order: 9, type: 'final_decision', data: { reason: trace.finalDecisionReason } },
   309→      {
   310→        order: 10,
   311→        type: 'action_determination',
   312→        data: {
   313→          determinedActions: result.determinedActions || [],
   314→          actionReasoning: result.finalClassificationSummary?.determinedActions
   315→            ? `Actions: ${result.finalClassificationSummary.determinedActions.join(', ')}`
   316→            : 'No actions determined',
   317→        },
   318→      },
   319→    ];
   320→
   321→    for (const stage of stageMapping) {
   322→      stages.push({
   323→        sessionId: sessionId,
   324→        stageOrder: stage.order,
   325→        stageType: stage.type,
   326→        startedAt: new Date(),
   327→        endedAt: new Date(),
   328→        features: stage.data as Prisma.InputJsonValue,
   329→        keywords: [],
   330→        passedToNext: true,
   331→      });
   332→    }
   333→
   334→    return stages;
   335→  }
   336→
   337→  /**
   338→   * Build stage category evaluation data from score breakdown
   339→   */
   340→  private async buildCategoryEvalData(
   341→    result: ClassificationResult,
   342→    sessionId: bigint
   343→  ): Promise<Array<Prisma.StageCategoryEvalCreateManyInput>> {
   344→    const evaluations: Array<Prisma.StageCategoryEvalCreateManyInput> = [];
   345→    const scoreBreakdown = result.scoreBreakdown;
   346→
   347→    // Extract category scores and create evaluations
   348→    for (const [category, scores] of Object.entries(scoreBreakdown.categoryScores || {})) {
   349→      try {
   350→        const categoryId = await this.getCategoryIdFromCode(category);
   351→        evaluations.push({
   352→          stageId: sessionId, // Simplified: using session_id as stage_id for MVP
   353→          categoryId: categoryId,
   354→          decision: result.selectedLabels.some((label) => label.category === category) ? 'positive' : 'candidate',
   355→          score: scores as unknown as Prisma.InputJsonValue,
   356→          confidence: new Prisma.Decimal(scores.finalScore || 0),
   357→          scoringComponents: scores as unknown as Prisma.InputJsonValue,
   358→          keywords: [],
   359→          createdAt: new Date(),
   360→        });
   361→      } catch (error) {
   362→        // Log warning and skip unknown category (graceful degradation)
   363→        console.warn(
   364→          `Skipping category evaluation for unknown category '${category}': ${error instanceof Error ? error.message : String(error)}`
   365→        );
   366→      }
   367→    }
   368→
   369→    return evaluations;
   370→  }
   371→
   372→  /**
   373→   * Build session category data (multi-label support)
   374→   */
   375→  private async buildSessionCategoryData(
   376→    result: ClassificationResult,
   377→    sessionId: bigint
   378→  ): Promise<Array<Prisma.SessionCategoryCreateManyInput>> {
   379→    const categories: Array<Prisma.SessionCategoryCreateManyInput> = [];
   380→
   381→    for (const label of result.selectedLabels) {
   382→      try {
   383→        const categoryId = await this.getCategoryIdFromCode(label.category);
   384→        const subtypeId = label.subtype ? await this.getCategoryIdFromCode(label.subtype) : null;
   385→
   386→        categories.push({
   387→          sessionId: sessionId,
   388→          categoryId: categoryId,
   389→          subtypeId: subtypeId,
   390→          isPrimary: label.isPrimary,
   391→          confidence: new Prisma.Decimal(label.confidence),
   392→          categoryScore: new Prisma.Decimal(label.score),
   393→          hardAssertion: false, // TODO: Extract from explainability trace
   394→          aiClassified: result.aiRoutingUsed,
   395→          scoringTrace: result.scoreBreakdown as unknown as Prisma.InputJsonValue,
   396→          labelOrder: label.labelOrder,
   397→          createdAt: new Date(),
   398→        });
   399→      } catch (error) {
   400→        // Log warning and skip unknown category (graceful degradation)
   401→        console.warn(
   402→          `Skipping session category for unknown category '${label.category}': ${error instanceof Error ? error.message : String(error)}`
   403→        );
   404→      }
   405→    }
   406→
   407→    return categories;
   408→  }
   409→
   410→  /**
   411→   * Build detected attribute data from attribute context
   412→   *
   413→   * Maps attribute context to database records with complete detection metadata,
   414→   * influence tracking, and temporal signals. Handles:
   415→   * - Urgency levels with detection metadata
   416→   * - Domain attributes with influence tracking
   417→   * - Structural patterns with evidence
   418→   * - Temporal signals (NEW: T043.4)
   419→   * - Influence applications with score impacts (NEW: T043.4)
   420→   * - Derived attributes (NEW: T043.4)
   421→   *
   422→   * @param context - AttributeContext with detected attributes and metadata
   423→   * @param sessionId - Session identifier as bigint
   424→   * @returns Array of detected attribute records for database insertion
   425→   */
   426→  private buildAttributeData(
   427→    context: AttributeContext,
   428→    sessionId: bigint
   429→  ): Array<Prisma.DetectedAttributeCreateManyInput> {
   430→    const attributes: Array<Prisma.DetectedAttributeCreateManyInput> = [];
   431→
   432→    // Helper to extract detection metadata
   433→    const getDetectionMetadata = (attributeKey: string) => {
   434→      return context.detectionMetadata?.[attributeKey];
   435→    };
   436→
   437→    // Helper to find influence applications for an attribute
   438→    const getInfluenceData = (attributeName: string) => {
   439→      const influences = context.influenceApplications?.filter((app) => app.attributeUsed === attributeName) || [];
   440→      const categoriesInfluenced = influences.map((app) => app.targetCategory);
   441→      const totalBonus = influences.reduce((sum, app) => sum + app.scoreImpact, 0);
   442→      const primaryRole = influences.length > 0 ? influences[0].roleType : 'NEUTRAL';
   443→      return { categoriesInfluenced, totalBonus, primaryRole };
   444→    };
   445→
   446→    // 1. Add urgency attribute
   447→    const urgencyMetadata = getDetectionMetadata('urgency');
   448→    const urgencyInfluence = getInfluenceData('urgency');
   449→    attributes.push({
   450→      sessionId: sessionId,
   451→      attributeName: 'urgency',
   452→      attributeValue: context.urgency,
   453→      detectionMethod: urgencyMetadata?.detectionMethod || 'rule',
   454→      detectionEvidence: urgencyMetadata?.evidence || `Urgency level: ${context.urgency}`,
   455→      influenceRole: urgencyInfluence.primaryRole,
   456→      categoriesInfluenced: urgencyInfluence.categoriesInfluenced,
   457→      totalBonusApplied: new Prisma.Decimal(urgencyInfluence.totalBonus),
   458→      createdAt: new Date(),
   459→    });
   460→
   461→    // 2. Add domain attributes
   462→    for (const domain of context.domains) {
   463→      const domainKey = `domain:${domain}`;
   464→      const domainMetadata = getDetectionMetadata(domainKey);
   465→      const domainInfluence = getInfluenceData(domainKey);
   466→
   467→      attributes.push({
   468→        sessionId: sessionId,
   469→        attributeName: domainKey,
   470→        attributeValue: domain,
   471→        detectionMethod: domainMetadata?.detectionMethod || 'domainLookup',
   472→        detectionEvidence: domainMetadata?.evidence || `Domain ${domain} detected in email`,
   473→        influenceRole: domainInfluence.primaryRole,
   474→        categoriesInfluenced: domainInfluence.categoriesInfluenced,
   475→        totalBonusApplied: new Prisma.Decimal(domainInfluence.totalBonus),
   476→        createdAt: new Date(),
   477→      });
   478→    }
   479→
   480→    // 3. Add structural pattern attributes
   481→    for (const pattern of context.structuralPatterns) {
   482→      const patternKey = `pattern:${pattern}`;
   483→      const patternMetadata = getDetectionMetadata(patternKey);
   484→      const patternInfluence = getInfluenceData(patternKey);
   485→
   486→      attributes.push({
   487→        sessionId: sessionId,
   488→        attributeName: patternKey,
   489→        attributeValue: pattern,
   490→        detectionMethod: patternMetadata?.detectionMethod || 'pattern',
   491→        detectionEvidence: patternMetadata?.evidence || `Structural pattern ${pattern} matched`,
   492→        influenceRole: patternInfluence.primaryRole,
   493→        categoriesInfluenced: patternInfluence.categoriesInfluenced,
   494→        totalBonusApplied: new Prisma.Decimal(patternInfluence.totalBonus),
   495→        createdAt: new Date(),
   496→      });
   497→    }
   498→
   499→    // 4. Add temporal signal attributes (NEW: T043.4)
   500→    for (const signal of context.temporalSignals) {
   501→      const signalKey = `temporal:${signal}`;
   502→      const signalMetadata = getDetectionMetadata(signalKey);
   503→      const signalInfluence = getInfluenceData(signalKey);
   504→
   505→      attributes.push({
   506→        sessionId: sessionId,
   507→        attributeName: signalKey,
   508→        attributeValue: signal,
   509→        detectionMethod: signalMetadata?.detectionMethod || 'temporalAnalysis',
   510→        detectionEvidence:
   511→          signalMetadata?.evidence || `Temporal signal ${signal} detected (e.g., time-sensitive keywords, deadlines)`,
   512→        influenceRole: signalInfluence.primaryRole,
   513→        categoriesInfluenced: signalInfluence.categoriesInfluenced,
   514→        totalBonusApplied: new Prisma.Decimal(signalInfluence.totalBonus),
   515→        createdAt: new Date(),
   516→      });
   517→    }
   518→
   519→    // 5. Add derived attributes (NEW: T043.4)
   520→    // Derived attributes are computed from other attributes (e.g., "is_self_sent" derived from from/to comparison)
   521→    for (const [derivedKey, derivedResult] of Object.entries(context.derivedAttributes || {})) {
   522→      const derivedInfluence = getInfluenceData(derivedKey);
   523→
   524→      attributes.push({
   525→        sessionId: sessionId,
   526→        attributeName: derivedKey,
   527→        attributeValue: String(derivedResult.calculatedValue),
   528→        detectionMethod: 'derived',
   529→        detectionEvidence: `Derived from: ${derivedResult.sourceAttributes.join(', ')} via ${derivedResult.derivationLogic}`,
   530→        influenceRole: derivedInfluence.primaryRole,
   531→        categoriesInfluenced: derivedInfluence.categoriesInfluenced,
   532→        totalBonusApplied: new Prisma.Decimal(derivedInfluence.totalBonus),
   533→        createdAt: new Date(),
   534→      });
   535→    }
   536→
   537→    // 6. Add influence applications that don't map to specific detected attributes (NEW: T043.4)
   538→    // Some influence applications may reference attributes not explicitly in the detected lists
   539→    // (e.g., attribute combinations, context-dependent influences)
   540→    const coveredAttributes = new Set([
   541→      'urgency',
   542→      ...context.domains.map((d) => `domain:${d}`),
   543→      ...context.structuralPatterns.map((p) => `pattern:${p}`),
   544→      ...context.temporalSignals.map((s) => `temporal:${s}`),
   545→      ...Object.keys(context.derivedAttributes || {}),
   546→    ]);
   547→
   548→    for (const influence of context.influenceApplications || []) {
   549→      if (!coveredAttributes.has(influence.attributeUsed)) {
   550→        // This is an influence from an attribute not explicitly tracked above
   551→        // (e.g., attribute combinations, implicit signals)
   552→        const metadata = getDetectionMetadata(influence.attributeUsed);
   553→
   554→        attributes.push({
   555→          sessionId: sessionId,
   556→          attributeName: influence.attributeUsed,
   557→          attributeValue: 'implicit', // No explicit value, inferred from influence
   558→          detectionMethod: metadata?.detectionMethod || 'derived',
   559→          detectionEvidence:
   560→            metadata?.evidence || `Implicit influence on ${influence.targetCategory}: ${influence.applicationReason}`,
   561→          influenceRole: influence.roleType,
   562→          categoriesInfluenced: [influence.targetCategory],
   563→          totalBonusApplied: new Prisma.Decimal(influence.scoreImpact),
   564→          createdAt: new Date(),
   565→        });
   566→
   567→        // Mark as covered to avoid duplicates
   568→        coveredAttributes.add(influence.attributeUsed);
   569→      }
   570→    }
   571→
   572→    return attributes;
   573→  }
   574→
   575→  /**
   576→   * Build extracted feature data from AI feature extraction results
   577→   *
   578→   * Extracts AI-generated features from the explainability trace and creates
   579→   * database records linked to the AI routing stage (stage 8).
   580→   *
   581→   * Only called when AI routing was used (result.aiRoutingUsed = true).
   582→   *
   583→   * @param result - ClassificationResult with AI feature extraction data
   584→   * @param stageRecords - Created classification stages with IDs
   585→   * @returns Array of extracted feature records for database insertion
   586→   */
   587→  private buildExtractedFeatureData(
   588→    result: ClassificationResult,
   589→    stageRecords: Array<{ stageId: bigint; stageOrder: number }>
   590→  ): Array<Prisma.ExtractedFeatureCreateManyInput> {
   591→    const features: Array<Prisma.ExtractedFeatureCreateManyInput> = [];
   592→
   593→    // Find the AI routing stage (stage 8) to associate features with
   594→    const aiRoutingStage = stageRecords.find((stage) => stage.stageOrder === 8);
   595→    if (!aiRoutingStage) {
   596→      console.warn('AI routing stage not found in stage records, skipping feature extraction persistence');
   597→      return features;
   598→    }
   599→
   600→    // Extract AI feature extraction data from explainability trace
   601→    const aiResponse = result.explainabilityTrace?.aiRouting?.aiResponse;
   602→    if (!aiResponse?.extractedFeatures) {
   603→      // No AI features to persist (AI routing may have skipped feature extraction)
   604→      return features;
   605→    }
   606→
   607→    const extractedFeatures = aiResponse.extractedFeatures as {
   608→      semanticIntent?: {
   609→        primaryPurpose?: string;
   610→        actionRequired?: string;
   611→        urgencyLevel?: string;
   612→      };
   613→      categoryEnhancements?: Record<
   614→        string,
   615→        {
   616→          applies: boolean;
   617→          confidenceBoost: number;
   618→          evidence?: {
   619→            quotedPhrases?: string[];
   620→            keywords?: string[];
   621→            reasoning?: string;
   622→          };
   623→        }
   624→      >;
   625→    };
   626→
   627→    // Extract semantic intent features
   628→    if (extractedFeatures.semanticIntent) {
   629→      const intent = extractedFeatures.semanticIntent;
   630→
   631→      if (intent.primaryPurpose) {
   632→        features.push({
   633→          stageId: aiRoutingStage.stageId,
   634→          name: 'semantic_intent_primary_purpose',
   635→          value: intent.primaryPurpose,
   636→          importance: new Prisma.Decimal(0.8), // High importance for primary purpose
   637→          evidenceSnippet: null,
   638→          createdAt: new Date(),
   639→        });
   640→      }
   641→
   642→      if (intent.actionRequired) {
   643→        features.push({
   644→          stageId: aiRoutingStage.stageId,
   645→          name: 'semantic_intent_action_required',
   646→          value: intent.actionRequired,
   647→          importance: new Prisma.Decimal(0.7),
   648→          evidenceSnippet: null,
   649→          createdAt: new Date(),
   650→        });
   651→      }
   652→
   653→      if (intent.urgencyLevel) {
   654→        features.push({
   655→          stageId: aiRoutingStage.stageId,
   656→          name: 'semantic_intent_urgency_level',
   657→          value: intent.urgencyLevel,
   658→          importance: new Prisma.Decimal(0.6),
   659→          evidenceSnippet: null,
   660→          createdAt: new Date(),
   661→        });
   662→      }
   663→    }
   664→
   665→    // Extract category enhancement features
   666→    if (extractedFeatures.categoryEnhancements) {
   667→      for (const [category, enhancement] of Object.entries(extractedFeatures.categoryEnhancements)) {
   668→        if (enhancement.applies && enhancement.confidenceBoost > 0) {
   669→          // Create a feature record for this category enhancement
   670→          const evidenceSnippet =
   671→            enhancement.evidence?.quotedPhrases && enhancement.evidence.quotedPhrases.length > 0
   672→              ? enhancement.evidence.quotedPhrases.slice(0, 3).join(' | ') // First 3 quoted phrases
   673→              : enhancement.evidence?.reasoning || null;
   674→
   675→          features.push({
   676→            stageId: aiRoutingStage.stageId,
   677→            name: `category_enhancement_${category}`,
   678→            value: `boost:${enhancement.confidenceBoost}`,
   679→            importance: new Prisma.Decimal(Math.min(enhancement.confidenceBoost / 100, 1.0)), // Normalize to 0-1
   680→            evidenceSnippet: evidenceSnippet ? evidenceSnippet.substring(0, 500) : null, // Limit length
   681→            createdAt: new Date(),
   682→          });
   683→
   684→          // If there are keywords, create a separate feature for them
   685→          if (enhancement.evidence?.keywords && enhancement.evidence.keywords.length > 0) {
   686→            features.push({
   687→              stageId: aiRoutingStage.stageId,
   688→              name: `category_keywords_${category}`,
   689→              value: enhancement.evidence.keywords.slice(0, 10).join(', '), // First 10 keywords
   690→              importance: new Prisma.Decimal(0.5),
   691→              evidenceSnippet: null,
   692→              createdAt: new Date(),
   693→            });
   694→          }
   695→        }
   696→      }
   697→    }
   698→
   699→    return features;
   700→  }
   701→
   702→  /**
   703→   * Get category ID from category code
   704→   *
   705→   * Uses cached category lookup for performance. Cache is initialized
   706→   * on first use and persists for the lifetime of the repository instance.
   707→   *
   708→   * @param code - Category code (e.g., 'finance', 'personal')
   709→   * @returns Category ID from database
   710→   * @throws {Error} If category code not found in database
   711→   */
   712→  private async getCategoryIdFromCode(code: string): Promise<number> {
   713→    // Initialize cache on first use
   714→    if (this.categoryCache === null) {
   715→      await this.initializeCategoryCache();
   716→    }
   717→
   718→    const categoryId = this.categoryCache!.get(code);
   719→    if (categoryId === undefined) {
   720→      throw new Error(
   721→        `Category code '${code}' not found in database. Available categories: ${Array.from(this.categoryCache!.keys()).join(', ')}`
   722→      );
   723→    }
   724→
   725→    return categoryId;
   726→  }
   727→
   728→  /**
   729→   * Close the Prisma client connection
   730→   *
   731→   * Only closes if using default Prisma instance (not externally provided).
   732→   */
   733→  async close(): Promise<void> {
   734→    if (this.ownsPrisma) {
   735→      await this.prisma.$disconnect();
   736→    }
   737→  }
   738→}
   739→

